using UnityEditor;
using UnityEngine;
using System.Linq;

public class AvatarSwapper
{
    public static string Swap()
    {
        string modelPath = "Assets/Models/modelwithrig.fbx";
        var assets = AssetDatabase.LoadAllAssetsAtPath(modelPath);
        Avatar newAvatar = assets.OfType<Avatar>().FirstOrDefault();

        if (newAvatar == null) 
            return "New Avatar not found in modelwithrig.fbx. Make sure it's imported as Humanoid.";

        Animator anim = (Animator)EditorUtility.InstanceIDToObject(54502);
        if (anim == null) 
            return "Animator not found on PlayerModel. Check if instanceID 54502 is still valid.";

        anim.avatar = newAvatar;
        EditorUtility.SetDirty(anim);
        AssetDatabase.SaveAssets();

        return $"Successfully swapped Avatar to: {newAvatar.name} from {modelPath}";
    }
}
